247	const PENDING_ATTENTION_LABELS: Record<string, string> = {
248	  'insert pending_attention{kind=bootstrap_failed}': 'bootstrap_failed',
249	  'insert pending_attention': 'awaiting_user_retry',
250	  'insert pending_attention{kind=revisit_limit}': 'revisit_limit',
251	  'insert pending_attention{kind=stage_needs_approval}': 'stage_needs_approval',
252	};
253	
254	function pendingAttentionKindFromEffects(
255	  sideEffects: readonly string[],
256	): string | null {
257	  for (const effect of sideEffects) {
258	    const kind = PENDING_ATTENTION_LABELS[effect];
259	    if (kind) return kind;
260	    // Fuzzy match for labels containing 'pending_attention'
261	    if (effect.includes('pending_attention') && effect.includes('insert')) {
262	      const m = /kind=([^}]+)/.exec(effect);
263	      return m ? m[1] : 'awaiting_user_retry';
264	    }
265	  }
266	  return null;
267	}
