629	        sideEffects: o[0].sideEffects,
630	        retryMode: retryMode as Exclude<RetryMode, 'awaiting_user'>,
631	      };
632	    }
633	
634	    default:
635	      throw new Error(
636	        `Unhandled conditional transition guard for (${currentState}, ${event})`,
637	      );
638	  }
639	}
